-- ----------------------------------------------------------------------------
-- vw_customers: Table: Customers
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_customers WITH (security_invoker = ON) AS
SELECT
  t.customer_id,
  t.name,                                                                       -- Human-readable customer name.
  t.notes,                                                                      -- Free-form notes about the customer.
  calc_customers_is_stopped(t.customer_id) AS is_stopped,                       -- True when the customer's current Status is a blocking status. Lookup of Statuses.IsBlocking.
  calc_customers_status_is_blocking(t.customer_id) AS status_is_blocking,       -- True when the customer's current Status is a blocking status. Lookup of Statuses.IsBlocking.
  t.status,                                                                     -- Link to the customer's current Status in the Statuses table.
  calc_customers_status_display_name(t.customer_id) AS status_display_name,     -- Human-readable display name of the customer's current Status. Lookup of Statuses.DisplayName.
  calc_customers_status_description(t.customer_id) AS status_description,       -- Description of the customer's current Status. Lookup of Statuses.Description.
  calc_customers_orders(t.customer_id) AS orders,                               -- Reverse link to all Orders placed by this customer.
  t.email,                                                                      -- Primary email address for the customer.
  t.phone,                                                                      -- Primary phone number for the customer.
  t.company_name,                                                               -- Company the customer represents, if applicable.
  t.billing_address,                                                            -- Default billing address for the customer.
  t.shipping_address,                                                           -- Default shipping address for the customer.
  t.created_at,                                                                 -- Timestamp when the customer record was created.
  calc_customers_average_order_value(t.customer_id) AS average_order_value,
  calc_customers_lifetime_margin_percent(t.customer_id) AS lifetime_margin_percent,
  calc_customers_customer_since_days(t.customer_id) AS customer_since_days,
  calc_customers_days_since_last_order(t.customer_id) AS days_since_last_order,
  calc_customers_count_of_multiple_payment_orders(t.customer_id) AS count_of_multiple_payment_orders,
  calc_customers_has_multi_payment_orders(t.customer_id) AS has_multi_payment_orders
FROM customers t;

-- ----------------------------------------------------------------------------
-- vw_statuses: Table: Statuses
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_statuses WITH (security_invoker = ON) AS
SELECT
  t.statuse_id,
  calc_statuses_name(t.statuse_id) AS name,                                     -- Lowercase, dash-separated compound key derived from DisplayName. Used as the natural key for the status.
  t.display_name,                                                               -- Human-readable display name of the status (e.g., "On-Hold", "In-Review").
  t.description,                                                                -- Free-form description of what this status means and when it applies.
  t.is_blocking,                                                                -- True when customers in this status should be considered stopped (blocked from progressing).
  calc_statuses_customers(t.statuse_id) AS customers,                           -- Reverse link to all Customers currently in this status.
  t.sort_order                                                                  -- Display order for this status in lists.
FROM statuses t;

-- ----------------------------------------------------------------------------
-- vw_products: Table: Products
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_products WITH (security_invoker = ON) AS
SELECT
  t.product_id,
  calc_products_name(t.product_id) AS name,                                     -- Lowercase, dash-separated compound key derived from SKU. Used as the natural key for the product.
  t.sku,                                                                        -- Stock-keeping unit identifier for the product. The natural compound key.
  calc_products_order_line_items(t.product_id) AS order_line_items,             -- Reverse link to all OrderLineItems that reference this product.
  t.display_name,                                                               -- Human-readable product name shown in catalogs and orders.
  t.description,                                                                -- Long-form product description.
  t.unit_price,                                                                 -- Default list price per unit.
  t.cost,                                                                       -- Internal cost per unit.
  t.is_active,                                                                  -- True when the product is currently sellable.
  t.stock_quantity                                                              -- Number of units currently in stock.
FROM products t;

-- ----------------------------------------------------------------------------
-- vw_orders: Table: Orders
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_orders WITH (security_invoker = ON) AS
SELECT
  t.order_id,
  calc_orders_name(t.order_id) AS name,                                         -- Lowercase compound key combining the linked Customer and OrderNumber (e.g. 'bob-1001'). Used as the natural key for the order.
  t.order_number,                                                               -- Sequential or human-assigned order identifier (e.g. '1001'). Combined with Customer to form the order's natural key.
  t.customer,                                                                   -- Link to the Customer who placed this order.
  calc_orders_order_line_items(t.order_id) AS order_line_items,                 -- Reverse link to all OrderLineItems on this order.
  calc_orders_payments(t.order_id) AS payments,                                 -- Reverse link to all Payments applied to this order.
  t.order_date,                                                                 -- When the order was placed.
  t.order_status,                                                               -- Lifecycle state of the order.
  t.shipping_address,                                                           -- Where this specific order ships to.
  t.billing_address,                                                            -- Billing address used for this specific order.
  t.notes,                                                                      -- Free-form notes about this order.
  calc_orders_item_count(t.order_id) AS item_count,
  calc_orders_total_quantity(t.order_id) AS total_quantity,
  calc_orders_sub_total(t.order_id) AS sub_total,
  t.tax_rate,                                                                   -- Sales tax rate applied to this order.
  calc_orders_tax_amount(t.order_id) AS tax_amount,
  calc_orders_order_total(t.order_id) AS order_total,
  calc_orders_total_paid(t.order_id) AS total_paid,
  calc_orders_amount_due(t.order_id) AS amount_due,
  calc_orders_is_paid_in_full(t.order_id) AS is_paid_in_full,
  calc_orders_payment_count(t.order_id) AS payment_count,
  calc_orders_is_multi_payment_order(t.order_id) AS is_multi_payment_order,
  calc_orders_last_payment_date(t.order_id) AS last_payment_date,
  calc_orders_payment_status_label(t.order_id) AS payment_status_label
FROM orders t;

-- ----------------------------------------------------------------------------
-- vw_order_line_items: Table: OrderLineItems
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_order_line_items WITH (security_invoker = ON) AS
SELECT
  t.order_line_item_id,
  calc_order_line_items_name(t.order_line_item_id) AS name,                     -- Lowercase compound key combining the linked Order and LineNumber (e.g. 'bob-1001-line-1'). Used as the natural key for the line item.
  t.line_number,                                                                -- Position of this line within its parent Order (e.g. '1', '2'). Combined with Order to form the line item's natural key.
  t."order",                                                                    -- Link to the parent Order this line item belongs to.
  t.product,                                                                    -- Link to the Product being ordered on this line.
  t.quantity,                                                                   -- Number of units ordered on this line.
  t.unit_price,                                                                 -- Price per unit captured at the time of ordering (may differ from current Product.UnitPrice).
  calc_order_line_items_pre_discount(t.order_line_item_id) AS pre_discount,
  t.discount_percent,                                                           -- Per-line discount applied to this item.
  calc_order_line_items_discount_amount(t.order_line_item_id) AS discount_amount,
  calc_order_line_items_sub_total(t.order_line_item_id) AS sub_total,
  t.notes                                                                       -- Free-form notes about this line item.
FROM order_line_items t;

-- ----------------------------------------------------------------------------
-- vw_payments: Table: Payments
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_payments WITH (security_invoker = ON) AS
SELECT
  t.payment_id,
  calc_payments_name(t.payment_id) AS name,                                     -- Lowercase compound key combining the linked Order and PaymentNumber (e.g. 'bob-1001-pmt-1'). Used as the natural key for the payment.
  t.payment_number,                                                             -- Sequential payment identifier within the parent Order (e.g. '1', '2'). Combined with Order to form the payment's natural key.
  t."order",                                                                    -- Link to the Order this payment is being applied to.
  t.payment_date,                                                               -- When the payment was received.
  t.payment_method,                                                             -- How the payment was made.
  t.transaction_id,                                                             -- External processor transaction identifier.
  t.notes,                                                                      -- Free-form notes about this payment.
  calc_payments_order_date(t.payment_id) AS order_date,
  calc_payments_order_number(t.payment_id) AS order_number,
  calc_payments_order_status(t.payment_id) AS order_status,
  calc_payments_order_total(t.payment_id) AS order_total,
  t.amount,                                                                     -- Amount paid.
  t.payment_status,                                                             -- Lifecycle state of the payment.
  calc_payments_is_completed(t.payment_id) AS is_completed,
  calc_payments_completed_amount(t.payment_id) AS completed_amount,
  calc_payments_order_amount_due(t.payment_id) AS order_amount_due,
  calc_payments_order_is_paid_in_full(t.payment_id) AS order_is_paid_in_full
FROM payments t;

